+//! Summary output format tests for pt-core.
+
+use assert_cmd::cargo::cargo_bin_cmd;
+use assert_cmd::Command;
+use predicates::prelude::*;
+use tempfile::tempdir;
+
+fn pt_core() -> Command {
+    cargo_bin_cmd!("pt-core")
